-- LUCIDOTA workflow registry: small inspectable catalog for ABSURD-owned workflows.

CREATE SCHEMA IF NOT EXISTS lucidota_control;

CREATE TABLE IF NOT EXISTS lucidota_control.workflow_registry (
    workflow_name text PRIMARY KEY,
    owner text NOT NULL DEFAULT 'absurd',
    phase text NOT NULL,
    status text NOT NULL CHECK (status IN ('planned','prototype','active','deprecated')),
    command text NOT NULL DEFAULT '',
    inputs jsonb NOT NULL DEFAULT '{}'::jsonb,
    outputs jsonb NOT NULL DEFAULT '{}'::jsonb,
    notes text NOT NULL DEFAULT '',
    updated_at timestamptz NOT NULL DEFAULT now()
);

ON CONFLICT (workflow_name) DO UPDATE SET
    owner=EXCLUDED.owner,
    phase=EXCLUDED.phase,
    status=EXCLUDED.status,
    command=EXCLUDED.command,
    inputs=EXCLUDED.inputs,
    outputs=EXCLUDED.outputs,
    notes=EXCLUDED.notes,
    updated_at=now();
